 {"id":"bd-3ey","title":"Create unified HandlerRegistryRenderer for complete capability display","description":"## Purpose and Rationale

Create a unified renderer that displays all server capabilities (tools, resources, prompts) in a comprehensive, well-organized format. This provides a single-call way to show everything a server exposes.

## Background

While individual renderers are useful, operators often want to see the complete picture of what a server exposes. The HandlerRegistryRenderer combines tools, resources, and prompts into a cohesive display with proper sections and summaries.

## Technical Specification

### Core Structure

```rust
// crates/fastmcp-console/src/handlers/registry.rs

use crate::console::FastMcpConsole;
use crate::theme::FastMcpTheme;
use crate::context::DisplayContext;
use crate::handlers::{ToolTableRenderer, ResourceTableRenderer, PromptTableRenderer};
use fastmcp::server::ServerCapabilities;
use rich_rust::{Panel, Rule, Table, Column};

/// Unified renderer for complete server capabilities
pub struct HandlerRegistryRenderer {
    tool_renderer: ToolTableRenderer,
    resource_renderer: ResourceTableRenderer,
    prompt_renderer: PromptTableRenderer,
    theme: FastMcpTheme,
    context: DisplayContext,
}

impl HandlerRegistryRenderer {
    pub fn new(theme: FastMcpTheme, context: DisplayContext) -> Self {
        Self {
            tool_renderer: ToolTableRenderer::new(theme.clone(), context.clone()),
            resource_renderer: ResourceTableRenderer::new(theme.clone(), context.clone()),
            prompt_renderer: PromptTableRenderer::new(theme.clone(), context.clone()),
            theme,
            context,
        }
    }

    /// Render complete server capabilities
    pub fn render(&self, capabilities: &ServerCapabilities, console: &FastMcpConsole) {
        if !self.context.should_use_rich() {
            self.render_plain(capabilities, console);
            return;
        }

        // Header
        self.render_summary_header(capabilities, console);

        // Tools section
        if !capabilities.tools.is_empty() {
            console.print("");
            self.tool_renderer.render(&capabilities.tools, console);
        }

        // Resources section
        if !capabilities.resources.is_empty() {
            console.print("");
            self.resource_renderer.render(&capabilities.resources, console);
        }

        // Prompts section
        if !capabilities.prompts.is_empty() {
            console.print("");
            self.prompt_renderer.render(&capabilities.prompts, console);
        }

        // Footer
        self.render_footer(capabilities, console);
    }

    /// Render a compact summary panel
    pub fn render_summary(&self, capabilities: &ServerCapabilities, console: &FastMcpConsole) {
        if !self.context.should_use_rich() {
            self.render_summary_plain(capabilities, console);
            return;
        }

        let mut table = Table::new()
            .title("Server Capabilities")
            .with_column(Column::new("Type"))
            .with_column(Column::new("Count").justify(rich_rust::JustifyMethod::Right))
            .with_column(Column::new("Status"));

        // Tools
        let tools_status = if capabilities.tools.is_empty() { 
            "[dim]none[/]" 
        } else { 
            "[green]available[/]" 
        };
        table.add_row_cells(["📦 Tools", &capabilities.tools.len().to_string(), tools_status]);

        // Resources
        let resources_status = if capabilities.resources.is_empty() { 
            "[dim]none[/]" 
        } else { 
            "[green]available[/]" 
        };
        table.add_row_cells(["📄 Resources", &capabilities.resources.len().to_string(), resources_status]);

        // Prompts
        let prompts_status = if capabilities.prompts.is_empty() { 
            "[dim]none[/]" 
        } else { 
            "[green]available[/]" 
        };
        table.add_row_cells(["💬 Prompts", &capabilities.prompts.len().to_string(), prompts_status]);

        console.print_renderable(&table);
    }

    fn render_summary_header(&self, capabilities: &ServerCapabilities, console: &FastMcpConsole) {
        let total = capabilities.tools.len() + capabilities.resources.len() + capabilities.prompts.len();

        let rule = Rule::with_title(format!("🚀 Server Capabilities ({} total)", total))
            .style(self.theme.primary_style());
        console.print_renderable(&rule);
    }

    fn render_footer(&self, capabilities: &ServerCapabilities, console: &FastMcpConsole) {
        let tools = capabilities.tools.len();
        let resources = capabilities.resources.len();
        let prompts = capabilities.prompts.len();

        console.print("");
        console.print(&format!(
            "[dim]Summary: {} tool{}, {} resource{}, {} prompt{}[/]",
            tools, if tools == 1 { "" } else { "s" },
            resources, if resources == 1 { "" } else { "s" },
            prompts, if prompts == 1 { "" } else { "s" }
        ));
    }

    fn render_plain(&self, capabilities: &ServerCapabilities, console: &FastMcpConsole) {
        let total = capabilities.tools.len() + capabilities.resources.len() + capabilities.prompts.len();
        console.print(&format!("=== Server Capabilities ({} total) ===", total));

        if !capabilities.tools.is_empty() {
            self.tool_renderer.render(&capabilities.tools, console);
        }
        if !capabilities.resources.is_empty() {
            self.resource_renderer.render(&capabilities.resources, console);
        }
        if !capabilities.prompts.is_empty() {
            self.prompt_renderer.render(&capabilities.prompts, console);
        }
    }

    fn render_summary_plain(&self, capabilities: &ServerCapabilities, console: &FastMcpConsole) {
        console.print("Server Capabilities:");
        console.print(&format!("  Tools: {}", capabilities.tools.len()));
        console.print(&format!("  Resources: {}", capabilities.resources.len()));
        console.print(&format!("  Prompts: {}", capabilities.prompts.len()));
    }
}
```

