### Logging/Tracing Requirements

```rust
use tracing::{debug, info, warn, instrument, Span};

impl McpContext {
    #[instrument(level = "debug", skip(self), fields(uri = %uri, depth = self.inner.resource_read_depth))]
    pub async fn read_resource(&self, uri: &str) -> McpResult<ReadResourceResult> {
        debug!("Reading resource from handler context");

        if self.inner.resource_read_depth >= MAX_RESOURCE_READ_DEPTH {
            warn!(
                depth = self.inner.resource_read_depth,
                max = MAX_RESOURCE_READ_DEPTH,
                "Resource read depth limit exceeded"
            );
            return Err(McpError::internal("Maximum resource read depth exceeded"));
        }

        let router = self.inner.router.as_ref()
            .ok_or_else(|| {
                warn!("Attempted to read resource without router in context");
                McpError::internal("No router available in context")
            })?;

        let child_ctx = self.with_incremented_depth();
        debug!(new_depth = child_ctx.inner.resource_read_depth, "Created child context");

        let result = router.read_resource(&child_ctx, uri).await;

        match &result {
            Ok(r) => debug!(contents = r.contents.len(), "Resource read successful"),
            Err(e) => debug!(error = %e, "Resource read failed"),
        }

        result
    }
}
```

Required trace points:
- `DEBUG`: Resource read start with URI and depth
- `DEBUG`: Child context creation with new depth
- `WARN`: Depth limit exceeded, no router available
- `DEBUG`: Resource read completion or failure

